class FWFTextBlockReportTextInit
{
    public const str        FieldNameHeaderText = identifierStr(FWFTextBlockHeaderText);
    public const str        FieldNameFooterText = identifierStr(FWFTextBlockFooterText);
    public const str        FieldNameHeaderTextLine = identifierStr(FWFTextBlockHeaderTextLine);
    public const str        FieldNameFooterTextLine = identifierStr(FWFTextBlockFooterTextLine);

    Common                  target;
    Common                  source;
    FieldId                 fieldNoHeaderText;
    FieldId                 fieldNoFooterText;
}

Method.Source:
public void addTexts()
{
    FWFTextBlockInstance    instanceTrans;
    FWFTextBlockParm        instanceParm;
    FWFTextBlockValue       value;

    if (! fieldNoHeaderText && ! fieldNoFooterText)
    {
        return;
    }

    // TEST SQLs: Set breakpoint in DP.processReport() at end
    // -------------------------------------------------------
    // Always:
    //   set transaction isolation level read uncommitted
    // Always before first run:
    //   truncate table PURCHPURCHASEORDERHEADER (table depending on the document!)
    //   truncate table PURCHPURCHASEORDERTMP
    // Purchase order confirmation
    //   select FWFHEADERTEXT, FWFFOOTERTEXT, * from PURCHPURCHASEORDERHEADER
    //   select FWFHEADERTEXT, FWFFOOTERTEXT, * from PURCHPURCHASEORDERTMP
    // Purch receipt list
    //   select FWFHEADERTEXT, FWFFOOTERTEXT, * from PURCHRECEIPTSLISTHEADERTMP
    //   select FWFHEADERTEXT, FWFFOOTERTEXT, * from PURCHRECEIPTSLISTDETAILSTMP
    // ...

    while select RefRecId from instanceTrans
        order by instanceParm.Position, instanceParm.SortOrder
        where instanceTrans.RefRecId        == source.RecId
           && instanceTrans.RefTableId      == source.TableId
    join TextBlock from value
        where value.RecId == instanceTrans.ValueRecId
    join SortOrder, Position from instanceParm
        where instanceParm.RecId == instanceTrans.SetupRecId
    {
        if (instanceParm.Position == FWFTextBlockPosition::Above)
        {
            if (fieldNoHeaderText)
            {
                target.(fieldNoHeaderText) = value.htmlText(target.(fieldNoHeaderText));
            }
        }
        else
        {
            if (fieldNoFooterText)
            {
                target.(fieldNoFooterText) = value.htmlText(target.(fieldNoFooterText));
            }
        }
    }

    if ((target.(fieldNoHeaderText) || target.(fieldNoFooterText)) && target.RecId)
    {
        ttsBegin;
        target.selectForUpdate(true);
        target.update();
        ttsCommit;
    }
}

    public void addTextsTransferOrder()
    {
        FWFTextBlockInstance    instanceTrans;
        FWFTextBlockParm        instanceParm;
        FWFTextBlockValue       value;

        if (! fieldNoHeaderText && ! fieldNoFooterText)
        {
            return;
        }

        while select RefRecId from instanceTrans
            order by instanceParm.Position, instanceParm.SortOrder
            where instanceTrans.RefRecId        == source.RecId
               && instanceTrans.RefTableId      == source.TableId
        join TextBlock from value
            where value.RecId == instanceTrans.ValueRecId
        join SortOrder, Position from instanceParm
            where instanceParm.RecId == instanceTrans.SetupRecId
			   && instanceParm.PrintOnInventTransferOrder
        {
            if (instanceParm.Position == FWFTextBlockPosition::Above)
            {
                if (fieldNoHeaderText)
                {
                    target.(fieldNoHeaderText) = value.htmlText(target.(fieldNoHeaderText));
                }
            }
            else
            {
                if (fieldNoFooterText)
                {
                    target.(fieldNoFooterText) = value.htmlText(target.(fieldNoFooterText));
                }
            }
        }

        if ((target.(fieldNoHeaderText) || target.(fieldNoFooterText)) && target.RecId)
        {
            ttsBegin;
            target.selectForUpdate(true);
            target.update();
            ttsCommit;
        }
    }

public void addTextsProformaAgreement(SalesPurch _salesPurch)
{
    FWFTextBlockInstance    instanceTrans;
    FWFTextBlockParm        instanceParm;
    FWFTextBlockValue       value;

    if (! fieldNoHeaderText && ! fieldNoFooterText)
    {
        return;
    }

    while select RefRecId from instanceTrans
        order by instanceParm.Position, instanceParm.SortOrder
        where instanceTrans.RefRecId        == source.RecId
           && instanceTrans.RefTableId      == source.TableId
    join TextBlock from value
        where value.RecId == instanceTrans.ValueRecId
    join SortOrder, Position from instanceParm
        where instanceParm.RecId == instanceTrans.SetupRecId
        && ((_salesPurch == SalesPurch::Sales && instanceParm.PrintOnSalesAgreement) || (_salesPurch == SalesPurch::Purch && instanceParm.PrintOnPurchAgreement))
    {
        if (instanceParm.Position == FWFTextBlockPosition::Above)
        {
            if (fieldNoHeaderText)
            {
                target.(fieldNoHeaderText) = value.htmlText(target.(fieldNoHeaderText));
            }
        }
        else
        {
            if (fieldNoFooterText)
            {
                target.(fieldNoFooterText) = value.htmlText(target.(fieldNoFooterText));
            }
        }
    }

    if ((target.(fieldNoHeaderText) || target.(fieldNoFooterText)) && target.RecId)
    {
        ttsBegin;
        target.selectForUpdate(true);
        target.update();
        ttsCommit;
    }
}

public void addTextsProductionPaper(ProdJournalType	_prodJournalType)
{
    FWFTextBlockInstance    instanceTrans;
    FWFTextBlockParm        instanceParm;
    FWFTextBlockValue       value;

    if (! fieldNoHeaderText && ! fieldNoFooterText)
    {
        return;
    }

    while select RefRecId from instanceTrans
        order by instanceParm.Position, instanceParm.SortOrder
        where instanceTrans.RefRecId        == source.RecId
           && instanceTrans.RefTableId      == source.TableId
    join TextBlock from value
        where value.RecId == instanceTrans.ValueRecId
    join SortOrder, Position from instanceParm
        where instanceParm.RecId == instanceTrans.SetupRecId
        && ((_prodJournalType == ProdJournalType::JobCard   && instanceParm.PrintOnProdJobCard)
        ||  (_prodJournalType == ProdJournalType::RouteCard && instanceParm.PrintOnProdRouteCard)
        ||  (_prodJournalType == ProdJournalType::Picklist  && instanceParm.PrintOnProdPickList))
    {
        if (instanceParm.Position == FWFTextBlockPosition::Above)
        {
            if (fieldNoHeaderText)
            {
                target.(fieldNoHeaderText) = value.htmlText(target.(fieldNoHeaderText));
            }
        }
        else
        {
            if (fieldNoFooterText)
            {
                target.(fieldNoFooterText) = value.htmlText(target.(fieldNoFooterText));
            }
        }
    }

    if ((target.(fieldNoHeaderText) || target.(fieldNoFooterText)) && target.RecId)
    {
        ttsBegin;
        target.selectForUpdate(true);
        target.update();
        ttsCommit;
    }
}

/// <summary>
/// Adds extendes texts to report data provider table. Existing texts will be clear before.
/// </summary>
public void insTexts()
{
    this.initParameters();

    this.clearTexts();

    this.addTexts();
}

/// <summary>
/// Clears the 2 fields for header and footer text in target table.
/// </summary>
public void clearTexts()
{
    if (fieldNoHeaderText && fieldNoFooterText)
    {
        target.(fieldNoHeaderText) = '';
        target.(fieldNoFooterText) = '';
    }
}

/// <summary>
/// Adds extendes texts to report data provider table for lines. This method should be used, when there is only 1 table in report data
/// provider for both header and lines.
/// </summary>
public void addLineTexts()
{
    this.initParametersForLine();

    this.addTexts();
}

/// <summary>
/// Adds extendes texts to report data provider table for lines. Existing text will be cleared before. This method should be used, when there 
/// is only 1 table in report data provider for both header and lines.
/// </summary>
public void insLineTexts()
{
    this.initParametersForLine();

    this.clearTexts();

    this.addLineTexts();
}

private void initParametersForLine()
{
    fieldNoHeaderText = fieldName2id(target.TableId, FWFTextBlockReportTextInit::FieldNameHeaderTextLine);
    fieldNoFooterText = fieldName2id(target.TableId, FWFTextBlockReportTextInit::FieldNameFooterTextLine);
}

private void initParameters()
{
    fieldNoHeaderText = fieldName2id(target.TableId, FWFTextBlockReportTextInit::FieldNameHeaderText);
    fieldNoFooterText = fieldName2id(target.TableId, FWFTextBlockReportTextInit::FieldNameFooterText);
}

public FieldId parmFieldNoFooterText(FieldId _fieldNoFooterText = fieldNoFooterText)
{
    fieldNoFooterText = _fieldNoFooterText;

    return fieldNoFooterText;
}

public FieldId parmFieldNoHeaderText(FieldId _fieldNoHeaderText = fieldNoHeaderText)
{
    fieldNoHeaderText = _fieldNoHeaderText;

    return fieldNoHeaderText;
}

public Common parmSource(Common _source = source)
{
    source = _source;

    return source;
}

public Common parmTarget(Common _target = target)
{
    target = _target;

    return target;
}

public static FWFTextBlockReportTextInit construct()
{
    return new FWFTextBlockReportTextInit();
}

static FWFTextBlockReportTextInit newParameters(Common _target, Common _source)
{
    FWFTextBlockReportTextInit init = FWFTextBlockReportTextInit::construct();

    init.parmSource(_source);
    init.parmTarget(_target);
    init.initParameters();

    return init;
}

static FWFTextBlockReportTextInit newParametersPoConform(Common _target, PurchLineAllVersions _source, boolean _isProforma)
{
    Common source;

    if (_isProforma)
    {
        source = PurchLine::findRecId(_source.RecId);
    }
    else
    {
        if (_source.IsArchived)
        {
            source = PurchLineHistory::findRecId(_source.RecId);
        }
        else
        {
            source = _source;
        }
    }

    return FWFTextBlockReportTextInit::newParameters(_target, source);

}
